LAYER
	NAME "lotes_psad56"
	GROUP "COFOPRI"
	TYPE polygon
	PROCESSING "LABEL_NO_CLIP=1"
	#HEADER "plantillas/inicio.html"
	#TEMPLATE "plantillas/allpa/cofopri/lotes.html"
	#FOOTER "plantillas/fin.html"
	STATUS on
	DATA "geom FROM (SELECT gid, area_inscr, id_lote, id_mzna, nro_mzna, nro_lote, area_grafi, tip_uso, detalle_us, tip_contig, detalle_co, tip_predio, id_plano, id_dist, id_prov, id_dpto, tip_fuente, cuc, geom FROM cofopri.lotes_psad56) as sbn using unique gid using srid=4248"
    FILTER ("[id_dpto]" IN "08")
	INCLUDE "configuracion/postgresql_allpa.map"
	PROJECTION
		"init=epsg:4248"
	END
	CLASSITEM "gid"
	LABELMAXSCALEDENOM 2000000
	LABELMAXSCALE 2000000
	METADATA
		"wms_group_title" "COFOPRI"
		"queryable" "true"
		"wms_metadataurl_href" "LUISAMOS"
		"wms_metadataurl_format" "text/xml"
		"wms_metadataurl_type" "TC211"
		"wms_title" "Formalización - Lotes (PSAD56)"
		"wms_abstract" "Formalización - Lotes (PSAD56) || Organismo de Formalización de la Propiedad Informal - COFOPRI :: Perú"
		"wms_credit" "COFOPRI"
		"wms_dataurl" ""
		"wms_dataurl_format" "text/html"
		"wms_dataurl_href" ""
		"wms_extent" "-81.30675509 -17.20814673 -69.085388666 -3.49657417600002"
		"wms_srs" "EPSG:4248"
		"wms_include_items" "all"
		"wms_exclude_items" "gid"
		"wms_enable_request" "*"
	END
	CLASS
		NAME "Lotes"
		EXPRESSION /./
		STYLE
			COLOR -1 -1 -1
			OUTLINECOLOR 0 0 255
			WIDTH 1
		END
	END
END # Layer